## Phase 3: Platform tRPC CORS widening

### Overview

Accept any origin matching the dev portless set in dev; preserve strict equality otherwise.

### Changes Required:

#### 1. `apps/platform/src/app/(trpc)/api/trpc/[trpc]/route.ts`

**File**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/platform/src/app/(trpc)/api/trpc/[trpc]/route.ts`
**Changes**: Replace strict equality with a wildcard-aware allowlist in dev only.

```ts
import { createPlatformTRPCContext, platformRouter } from "@api/platform";
import { getPortlessProxyOrigins } from "@lightfastai/dev-proxy/next";
import { fetchRequestHandler } from "@trpc/server/adapters/fetch";
import type { NextRequest } from "next/server";
import { env } from "~/env";
import { appUrl } from "~/lib/related-projects";

export const runtime = "nodejs";

// Resolved at module load. In dev: ["app.lightfast.localhost", "*.app.lightfast.localhost", ...].
// In production/preview: [].
const devOrigins =
  env.NEXT_PUBLIC_VERCEL_ENV === undefined || env.NEXT_PUBLIC_VERCEL_ENV === "development"
    ? getPortlessProxyOrigins({ allowMissingConfig: true })
    : [];

function isAllowedOrigin(origin: string | null): origin is string {
  if (!origin) return false;
  if (origin === appUrl) return true;
  if (devOrigins.length === 0) return false;
  // Match against bare hostnames and *.subdomain wildcards from getPortlessProxyOrigins.
  // Each entry is either "host.tld" or "*.host.tld"; coerce origin to a hostname for matching.
  let originHost: string;
  try {
    originHost = new URL(origin).host;
  } catch {
    return false;
  }
  return devOrigins.some((pattern) => {
    if (pattern.startsWith("*.")) {
      const suffix = pattern.slice(1); // ".app.lightfast.localhost"
      return originHost.endsWith(suffix) && originHost.length > suffix.length;
    }
    return originHost === pattern;
  });
}

const setCorsHeaders = (req: NextRequest, res: Response) => {
  const origin = req.headers.get("origin");
  if (!isAllowedOrigin(origin)) return res;

  res.headers.set("Access-Control-Allow-Origin", origin);
  res.headers.set("Access-Control-Allow-Methods", "GET,POST,OPTIONS");
  res.headers.set("Access-Control-Allow-Headers", "content-type,authorization,x-trpc-source");
  res.headers.set("Vary", "Origin");
  res.headers.set("Access-Control-Allow-Credentials", "true");

  return res;
};

export const OPTIONS = (req: NextRequest) => {
  const response = new Response(null, { status: 204 });
  return setCorsHeaders(req, response);
};

const handler = async (req: NextRequest) => {
  const response = await fetchRequestHandler({
    endpoint: "/api/trpc",
    router: platformRouter,
    req,
    createContext: () => createPlatformTRPCContext({ headers: req.headers }),
  });
  return setCorsHeaders(req, response);
};

export { handler as GET, handler as POST };
```

